def generate_content(topic: str, brand_voice: str, max_turns: int = 5):
    conversation = stack.new_conversation()

    for turn in range(max_turns):
        response = conversation.send_message(
            f"Generate {topic} in {brand_voice} voice. "
            f"Include SEO keywords, cite facts, ensure originality."
        )

        # Vex verification happens here (see integration section)
        verified_content = verify(response.content, checks=content_checks())

        if verified_content.approved:
            return verified_content

    return conversation.finalize()

def optimize_for_seo(content: str, keywords: list):
    seo_result = stack.tools["seo_analyzer"].call(
        content=content,
        target_keywords=keywords
    )

    seo_score = verify(
        content,
        metrics=seo_result["scores"],
        checks=["seo_compliance", "keyword_density"]
    )

    if seo_score.score < 0.85:
        return stack.refine_content(content, seo_result["suggestions"])

    return content

