from vex import verify, Check

def content_checks():
    return [
        Check.brand_consistency(voice_profile="professional-casual"),
        Check.factual_accuracy(min_confidence=0.9),
        Check.originality(plagiarism_threshold=0.05),
        Check.tone_adherence(target_tone="engaging-authoritative"),
        Check.seo_compliance(keywords=["AI", "content", "generation"])
    ]

def safe_agent_turn(conversation):
    raw_response = conversation.send_message(user_prompt)

    result = verify(
        raw_response.content,
        checks=content_checks(),
        context=conversation.memory.context
    )

    if result.approved:
        return result.content
    else:
        return conversation.refine(result.issues)

def handle_safety_override(response):
    if response.safety_blocked:
        # Vex brand validation before safety shield
        brand_check = verify(
            response.content,
            checks=[Check.brand_consistency()],
            bypass_safety=True
        )

        if brand_check.approved:
            response.safety_score = 0.3  # Whitelist
            return response

    return verify(response.content, checks=content_checks())

from pydantic import BaseModel

class SEOAnalysis(BaseModel):
    score: float
    keywords: list[str]
    suggestions: list[str]

class FactCheck(BaseModel):
    verified: bool
    sources: list[str]

VEX_SCHEMAS = {
    "seo_analyzer": SEOAnalysis,
    "fact_check": FactCheck
}

def validate_tool_response(tool_name: str, response: str):
    schema = VEX_SCHEMAS.get(tool_name)

    validated = verify(
        response,
        schema=schema,
        checks=["json_schema_conformance"]
    )

    return validated.parsed if validated.approved else None
